bool SearchFilter::Filter([[maybe_unused]] int level, const Slice &key, [[maybe_unused]] const Slice &value,
                          [[maybe_unused]] std::string *new_value, [[maybe_unused]] bool *modified) const {
  auto db = stor_->GetDB();
  const auto cf_handles = stor_->GetCFHandles();
  // storage close would delete the column family handler and DB
  if (!db || cf_handles->size() < 2) return false;

  // Decode the search key to extract namespace and user key
  // Search key format: <namespace_size:1> <namespace> <type:1> <index> <field> ... <user_key>
  Slice input = key;

  // Extract namespace
  uint8_t ns_size = 0;
  if (!GetFixed8(&input, &ns_size)) {
    return false;  // Invalid key, keep it
  }

  if (input.size() < ns_size) {
    return false;  // Invalid key, keep it
  }

  Slice ns(input.data(), ns_size);
  input.remove_prefix(ns_size);

  // Extract type
  uint8_t type = 0;
  if (!GetFixed8(&input, &type)) {
    return false;  // Invalid key, keep it
  }

  auto subkey_type = static_cast<redis::SearchSubkeyType>(type);

  // We only filter FIELD data entries (tag, numeric, and HNSW nodes)
  // These are the entries that reference user keys
  if (subkey_type != redis::SearchSubkeyType::FIELD) {
    // Don't filter out metadata, prefixes, field_meta, or field_alias entries
    return false;
  }

  // Extract index name
  Slice index_name;
  if (!GetSizedString(&input, &index_name)) {
    return false;  // Invalid key, keep it
  }

  // Extract field name
  Slice field_name;
  if (!GetSizedString(&input, &field_name)) {
    return false;  // Invalid key, keep it
  }

  // Now we need to extract the user key, which varies by field type
  // For tag fields: <tag> <user_key>
  // For numeric fields: <number:8> <user_key>
  // For HNSW fields: <level:2> <level_type:1> <user_key> [<other_key>]

  Slice user_key;

  // Try to determine the field type and extract user key accordingly
  // For tag fields, skip the tag value
  if (input.size() >= 4) {  // Minimum size for a sized string
    // Try as tag field first
    Slice tag_value;
    Slice temp_input = input;
    if (GetSizedString(&temp_input, &tag_value) && GetSizedString(&temp_input, &user_key)) {
      // Successfully parsed as tag field
      input = temp_input;
    } else {
      // Try as numeric field: skip 8 bytes for double
      temp_input = input;
      if (temp_input.size() >= 8) {
        temp_input.remove_prefix(8);  // Skip the double value
        if (GetSizedString(&temp_input, &user_key)) {
          // Successfully parsed as numeric field
          input = temp_input;
        } else {
          // Try as HNSW field: skip 2 bytes for level and 1 byte for level_type
          temp_input = input;
          if (temp_input.size() >= 3) {
            temp_input.remove_prefix(3);  // Skip level (2 bytes) and level_type (1 byte)
            if (GetSizedString(&temp_input, &user_key)) {
              // Successfully parsed as HNSW field
              input = temp_input;
            } else {
              // Cannot parse, keep the entry
              return false;
            }
          } else {
            return false;
          }
        }
      } else {
        return false;
      }
    }
  } else {
    return false;  // Not enough data
  }

  // Now check if the metadata for this user key exists and is not expired
  std::string metadata_key = ComposeNamespaceKey(ns, user_key, stor_->IsSlotIdEncoded());
  std::string metadata_bytes;

  rocksdb::Status s = db->Get(rocksdb::ReadOptions(), (*cf_handles)[1], metadata_key, &metadata_bytes);

  if (s.IsNotFound()) {
    // Metadata doesn't exist, filter out this search entry
    debug("[compact_filter/search] Filtering out search entry for non-existent key, namespace: {}, key: {}",
          ns.ToString(), user_key.ToString());
    return true;
  }

  if (!s.ok()) {
    // Error reading metadata, keep the entry to be safe
    warn("[compact_filter/search] Failed to read metadata, namespace: {}, key: {}, err: {}",
         ns.ToString(), user_key.ToString(), s.ToString());
    return false;
  }

  // Decode metadata to check if it's expired
  Metadata metadata(kRedisNone, false);
  rocksdb::Status decode_status = metadata.Decode(metadata_bytes);

  if (!decode_status.ok()) {
    warn("[compact_filter/search] Failed to decode metadata, namespace: {}, key: {}, err: {}",
         ns.ToString(), user_key.ToString(), decode_status.ToString());
    return false;
  }

  // Check if metadata is expired
  bool expired = metadata.Expired();

  debug("[compact_filter/search] namespace: {}, key: {}, result: {}",
        ns.ToString(), user_key.ToString(), (expired ? "deleted" : "reserved"));

  return expired;
}

}  // namespace engine

